65	/// A rule instance: one record node with premise / info / conclusion cells, built
66	/// from [`Fact`]s (the crate renders and wraps them).
67	#[derive(Clone, Debug)]
68	pub struct RuleInstance {
69	    pub temporal: String,
70	    pub rule: String,
71	    pub role: String,
72	    pub premises: Vec<Fact>,
73	    pub actions: Vec<Fact>,
74	    pub conclusions: Vec<Fact>,
75	    /// Per-rule fill color (a solver-side hash — a GAP; supplied by the caller).
76	    pub fillcolor: String,
77	    /// `black` on the light MSR palette, `white`/`black` on the role palette.
78	    pub fontcolor: String,
79	    /// If set, this record is packed into a `cluster_<label>` subgraph (§4).
80	    pub cluster: Option<ClusterRef>,
81	}
