83	impl RuleInstance {
84	    pub fn new(temporal: &str, rule: &str, fillcolor: &str) -> Self {
85	        RuleInstance {
86	            temporal: temporal.into(),
87	            rule: rule.into(),
88	            role: Role::UNDEFINED.into(),
89	            premises: Vec::new(),
90	            actions: Vec::new(),
91	            conclusions: Vec::new(),
92	            fillcolor: fillcolor.into(),
93	            fontcolor: "black".into(),
94	            cluster: None,
95	        }
96	    }
97	    pub fn premises(mut self, f: Vec<Fact>) -> Self {
98	        self.premises = f;
99	        self
100	    }
101	    pub fn actions(mut self, f: Vec<Fact>) -> Self {
102	        self.actions = f;
103	        self
104	    }
105	    pub fn conclusions(mut self, f: Vec<Fact>) -> Self {
106	        self.conclusions = f;
107	        self
108	    }
109	    pub fn role(mut self, r: &str, fontcolor: &str) -> Self {
110	        self.role = r.into();
111	        self.fontcolor = fontcolor.into();
112	        self
113	    }
114	    /// Pack this record into the `cluster_<label>` subgraph (BEHAVIOR.md §4).
115	    pub fn cluster(mut self, label: &str, color: &str) -> Self {
116	        self.cluster = Some(ClusterRef::new(label, color));
117	        self
118	    }
