560	/// `tup_sur` / `uni_sur` = Σ over top-level tuple / `(a++b)`-union arguments
561	/// of `elems + 1` (the round-10 occupancy law, pinned at n = 2,3,4,6 tuples
562	/// and 3,5,8 unions); `bmax` = the largest per-argument self-budget bonus
563	/// `⌊elems/2⌋ + 2` (arguments with ≥ 9 elements contribute 4); `sqa` = the
564	/// cell is a fact with exactly one argument that is a single-quoted constant
565	/// (enters only the fill weight); `nfunc` = number of function-application
566	/// nodes anywhere in the text (enters only the fill numerator).
567	///
568	/// Public for the corpus-analysis binaries (band/miss dumps); not a stable
569	/// interface.
570	pub struct CellShape {
571	    pub flat: usize,
572	    pub tup_sur: i64,
573	    pub uni_sur: i64,
574	    /// Recursive tuple/union occupancy surcharge (round-11 law): every
575	    /// tuple/union node contributes `elems + 1`, except a node whose
576	    /// IMMEDIATE parent is itself a tuple/union, which contributes
577	    /// `elems − 1` (probe K1: pair-of-pairs occupies flat + 3 + 1 + 1, the
578	    /// X-flip at 38 exactly; K2: a tuple inside a FUNC arg counts full
579	    /// `elems + 1`, flip at 39; K6 pins nested 6-tuples ≥ ~5).
580	    pub rec_sur: i64,
581	    /// [`CellShape::rec_sur`] with each node's contribution capped at 7 —
582	    /// the FILL-numerator variant (the r8 16/20-element grids refute the
583	    /// uncapped numerator; the K3 6-tuple pin `elems + 1 = 7` is preserved).
584	    pub rec_sur7: i64,
585	    pub bmax: i64,
586	    /// Top-level argument count of a padded fact (0 for non-facts).
587	    pub nargs: i64,
588	    /// The fact's LAST top-level argument is a tuple/union of >= 2 elements
589	    /// (round-11 bonus-gating candidate: WIT probe shows a mid-list tuple
590	    /// carries no self-budget bonus).
591	    pub last_tup: bool,
592	    pub sqa: bool,
593	    pub nfunc: i64,
594	}
595	
596	/// Split a term list at top-level `", "`, honoring nesting and quotes.
597	fn split_level(s: &str) -> Vec<&str> {
598	    let b: Vec<(usize, char)> = s.char_indices().collect();
599	    let mut parts = Vec::new();
600	    let (mut depth, mut inq, mut start) = (0i32, false, 0usize);
601	    let mut i = 0;
602	    while i < b.len() {
603	        let (pos, c) = b[i];
604	        if inq {
605	            if c == '\'' {
606	                inq = false;
607	            }
608	        } else {
609	            match c {
610	                '\'' => inq = true,
611	                '(' | '<' | '[' => depth += 1,
612	                ')' | '>' | ']' => depth -= 1,
613	                ',' if depth == 0 && i + 1 < b.len() && b[i + 1].1 == ' ' => {
614	                    parts.push(&s[start..pos]);
615	                    start = b[i + 1].0 + 1;
616	                    i += 1;
617	                }
618	                _ => {}
619	            }
620	        }
621	        i += 1;
622	    }
623	    parts.push(&s[start..]);
624	    parts
625	}
626	
627	/// Element count of a parenthesized top-level `++`-union `(a++b++…)`, 0 for
628	/// anything else.
629	fn union_elems(t: &str) -> i64 {
630	    if !(t.starts_with('(') && t.ends_with(')')) || t.len() < 2 {
631	        return 0;
632	    }
633	    let inner = &t[1..t.len() - 1];
634	    let b: Vec<char> = inner.chars().collect();
635	    let (mut depth, mut inq, mut n) = (0i32, false, 1i64);
636	    let mut i = 0;
637	    while i < b.len() {
638	        let c = b[i];
639	        if inq {
640	            if c == '\'' {
641	                inq = false;
642	            }
643	        } else {
644	            match c {
645	                '\'' => inq = true,
646	                '(' | '<' | '[' => depth += 1,
647	                ')' | '>' | ']' => depth -= 1,
648	                '+' if depth == 0 && i + 1 < b.len() && b[i + 1] == '+' => {
649	                    n += 1;
650	                    i += 1;
651	                }
652	                _ => {}
653	            }
654	        }
655	        i += 1;
656	    }
657	    if n >= 2 { n } else { 0 }
658	}
659	
660	/// Recursive tuple/union occupancy walk (round-11): a tuple/union node
661	/// contributes `elems + 1`, or `elems − 1` when its immediate parent is a
662	/// tuple/union; function applications are transparent (their tuple args count
663	/// full — probe K2). `in_tuple` = the immediate parent is a tuple/union.
664	fn rec_walk(t: &str, in_tuple: bool, sur: &mut i64) {
665	    rec_walk_cap(t, in_tuple, i64::MAX, sur)
666	}
667	
668	/// [`rec_walk`] with a per-node contribution cap (probe-fitting helper; the
669	/// corpus-analysis binaries sweep caps). Public for the band/miss dumps.
670	pub fn rec_surcharge_capped(flat: &str, cap: i64) -> i64 {
671	    let mut sur = 0i64;
672	    if let Some(open) = flat.find("( ") {
673	        if flat.ends_with(" )")
674	            && open + 2 <= flat.len() - 2
675	            && !flat[..open].contains(['(', ')', '<', '>', ' ', ','])
676	        {
677	            let inner = &flat[open + 2..flat.len() - 2];
678	            for a in split_level(inner) {
679	                rec_walk_cap(a.trim(), false, cap, &mut sur);
680	            }
681	        }
682	    }
683	    sur
684	}
685	
686	fn rec_walk_cap(t: &str, in_tuple: bool, cap: i64, sur: &mut i64) {
687	    let t = t.trim();
688	    if t.starts_with('<') && t.ends_with('>') && t.len() >= 2 {
689	        let elems = split_level(&t[1..t.len() - 1]);
690	        let e = elems.len() as i64;
691	        if e >= 2 {
692	            *sur += (if in_tuple { e - 1 } else { e + 1 }).min(cap);
693	        }
694	        for el in elems {
695	            rec_walk_cap(el, true, cap, sur);
696	        }
697	        return;
698	    }
699	    let ue = union_elems(t);
700	    if ue >= 2 {
701	        *sur += (if in_tuple { ue - 1 } else { ue + 1 }).min(cap);
702	        for part in split_top_unions_str(&t[1..t.len() - 1]) {
703	            rec_walk_cap(&part, true, cap, sur);
704	        }
705	        return;
706	    }
707	    // function application name(args): recurse into args (parent = func)
708	    if let Some(open) = t.find('(') {
709	        if open > 0
710	            && t.ends_with(')')
711	            && t.len() > open + 1
712	            && t[..open].chars().all(|c| c.is_alphanumeric() || c == '_' || c == '!')
713	        {
714	            let inner = &t[open + 1..t.len() - 1];
715	            let inner = inner.strip_prefix(' ').unwrap_or(inner);
716	            let inner = inner.strip_suffix(' ').unwrap_or(inner);
717	            for a in split_level(inner) {
718	                rec_walk_cap(a, false, cap, sur);
719	            }
720	        }
721	    }
722	}
723	
724	/// Split a union body at top-level `++` (delegates to
725	/// [`crate::doclayout::split_top_unions`]).
726	fn split_top_unions_str(s: &str) -> Vec<String> {
727	    crate::doclayout::split_top_unions(s)
728	}
729	
730	pub fn cell_shape(flat: &str) -> CellShape {
731	    let width = flat.chars().count();
732	    let (mut tup_sur, mut uni_sur, mut bmax) = (0i64, 0i64, 0i64);
733	    let mut rec_sur = 0i64;
734	    let mut nargs = 0i64;
735	    let mut last_tup = false;
736	    let mut rec_sur7 = 0i64;
737	    let mut sqa = false;
738	    if let Some(open) = flat.find("( ") {
739	        // a padded fact with at least one argument (`Name( )` has none)
740	        if flat.ends_with(" )")
741	            && open + 2 <= flat.len() - 2
742	            && !flat[..open].contains(['(', ')', '<', '>', ' ', ','])
743	        {
744	            let inner = &flat[open + 2..flat.len() - 2];
745	            let args = split_level(inner);
746	            nargs = args.len() as i64;
747	            for a in &args {
748	                let t = a.trim();
749	                let (elems, is_tuple) = if t.starts_with('<') && t.ends_with('>') {
750	                    (split_level(&t[1..t.len() - 1]).len() as i64, true)
751	                } else {
752	                    (union_elems(t), false)
753	                };
754	                if elems >= 2 {
755	                    if is_tuple {
756	                        tup_sur += elems + 1;
757	                    } else {
758	                        uni_sur += elems + 1;
759	                    }
760	                    bmax = bmax.max(if elems <= 8 { elems / 2 + 2 } else { 4 });
761	                }
762	                rec_walk(t, false, &mut rec_sur);
763	                rec_walk_cap(t, false, 7, &mut rec_sur7);
764	                if elems >= 2 {
765	                    last_tup = std::ptr::eq(a, args.last().unwrap());
766	                }
767	            }
768	            if args.len() == 1 {
769	                let a = args[0].trim();
770	                sqa = a.starts_with('\'')
771	                    && a.ends_with('\'')
772	                    && a.len() >= 2
773	                    && !a[1..a.len() - 1].contains('\'');
774	            }
775	        }
776	    }
777	    // function-application nodes: identifier directly followed by `(` with no
778	    // space after (the unpadded display form), e.g. `senc(`, `pk(`
779	    let bch: Vec<char> = flat.chars().collect();
780	    let mut nfunc = 0i64;
781	    for i in 1..bch.len() {
782	        if bch[i] == '('
783	            && (bch[i - 1].is_alphanumeric() || bch[i - 1] == '_')
784	            && (i + 1 >= bch.len() || bch[i + 1] != ' ')
785	        {
786	            nfunc += 1;
787	        }
788	    }
789	    CellShape { flat: width, tup_sur, uni_sur, rec_sur, rec_sur7, bmax, nargs, last_tup, sqa, nfunc }
790	}
791	
792	/// The per-cell fit **budgets** of one record group (all premises together, or
793	/// all conclusions together), from the cells' flat texts. Probe-derived layers
794	/// (BEHAVIOR.md §3f, rounds 9–11; every parameter pinned by live probe
795	/// batteries — QUERIES.log Sessions 9–11):
796	///
797	/// **Trigger, pass 1** (flat-sum). Each cell occupies `C_j = flat_j +
798	/// rec_sur_j` columns of the row, where `rec_sur` is the RECURSIVE
799	/// tuple/union surcharge: every tuple/union node contributes `elems + 1`,
800	/// except nodes directly inside another tuple/union, which contribute
801	/// `elems − 1` (round-11 K1/K2/K6: pair-of-pairs flips at 38, a tuple inside
802	/// a func arg counts full). Cell *i*'s pass-1 budget is
803	/// `max(87 + bonus_i − Σ_{j≠i} C_j, 20)`, `bonus_i` = the largest
804	/// `⌊elems/2⌋ + 2` over its top-level tuple/union args (4 at ≥ 9 elements),
805	/// applied ONLY when the fact's LAST argument is such a tuple/union
806	/// (round-11 WIT: a mid-list tuple carries no bonus); it wraps iff its flat
807	/// width exceeds the budget. A lone cell's budget is 87.
808	///
809	/// **Fill** (the ribbon a wrapping cell is laid out at):
810	/// `hd(87·N_i / (N_i + Σ_{j≠i} w_j·C_j))`, rounded half-DOWN (round-11
811	/// equal-pair probes), clamped to `[20, flat_i − 1]`, with the numerator
812	/// `N_i = flat_i + rec_sur7_i + nfunc_i` (round-11 K3: tuple args DO enter
813	/// the numerator at `elems + 1` — a 6-tuple receiver fills at 38 beside 60 —
814	/// with per-node contributions capped at 7: the r8 16/20-element grids
815	/// refute the uncapped sum)
816	/// and `w_j = 5/6` for single-quoted-atom siblings of a tuple/union-fact
817	/// receiver (round-9 Q/I series), else 1.
818	///
819	/// **Trigger, pass 2** (relief — round-11 battery I / TB / WIT): a
820	/// pass-1-wrapping cell is SAVED (renders flat) iff it fits in the room its
821	/// siblings actually occupy: `flat_i ≤ max(87 − Σ_{j≠i} charge_j, 20)`,
822	/// where a truly-broken wrapping sibling (its fill < flat − 2, i.e. beyond
823	/// the `)`-peel-only zone) charges its fill allocation and everything else
824	/// charges `C_j`; no bonus enters this comparison (IB: a tuple target beside
825	/// a wrapping 90-wide sibling fits only at the floor). This reproduces the
826	/// beside-65 fits-at-23/wraps-at-24 boundary and the TB4 flip at 47/48.
827	///
828	/// The residual is the documented ±1 coupled-`fits` noise (e.g. `[45, 43]`
829	/// saved but `[46, 42]` not — indistinguishable in closed form).
830	pub fn group_widths(cells: &[String]) -> Vec<usize> {
831	    group_widths_with(cells, &[])
832	}
833	
834	/// [`group_widths`] with caller-supplied per-cell width inputs. `overrides` is
835	/// either empty (all cells use display-text estimates — byte-identical to
836	/// [`group_widths`]) or one `Option<CellWidths>` per cell; each present field
837	/// of a present entry replaces the corresponding display-text estimate
838	/// (occupancy `C`, budget bonus, fill numerator) for that cell, and every
839	/// absent field falls back per-field. The display flat width itself always
840	/// comes from the text (it *is* the rendered content).
841	pub fn group_widths_with(cells: &[String], overrides: &[Option<CellWidths>]) -> Vec<usize> {
842	    let shapes: Vec<CellShape> = cells.iter().map(|t| cell_shape(t)).collect();
843	    let n = shapes.len();
844	    let full = FILL_WIDTH as i64; // 87
845	    let floor = MIN_CELL_BUDGET as i64;
846	    let ov = |i: usize| -> Option<&CellWidths> { overrides.get(i).and_then(|o| o.as_ref()) };
847	    // round half-DOWN: nearest integer, exact .5 toward zero (round-11 GB
848	    // equal-pair probes: [50,50]…[80,80] all allocate 43, not 44; archived
849	    // probe re-score 510/535 vs 503 half-up)
850	    let hd = |x: f64| -> i64 {
851	        let fl = x.floor();
852	        if (x - fl - 0.5).abs() < 1e-9 { fl as i64 } else { (x + 0.5).floor() as i64 }
853	    };
854	    let cs: Vec<i64> = shapes
855	        .iter()
856	        .enumerate()
857	        .map(|(i, s)| ov(i).and_then(|w| w.occupancy).unwrap_or(s.flat as i64 + s.rec_sur))
858	        .collect();
859	    let ctot: i64 = cs.iter().sum();
860	    // effective self width in the trigger comparisons (caller-overridable)
861	    let eff: Vec<i64> =
862	        (0..n).map(|i| ov(i).and_then(|w| w.trigger_width).unwrap_or(shapes[i].flat as i64)).collect();
863	    // pass 1: flat-sum trigger with the last-arg-gated bonus
864	    let mut budget1 = vec![0i64; n];
865	    let mut wrap1 = vec![false; n];
866	    for (i, sh) in shapes.iter().enumerate() {
867	        let bonus = ov(i)
868	            .and_then(|w| w.bonus)
869	            .unwrap_or(if sh.last_tup { sh.bmax } else { 0 });
870	        budget1[i] = if n == 1 { full } else { (full + bonus - (ctot - cs[i])).max(floor) };
871	        wrap1[i] = eff[i] > budget1[i];
872	    }
873	    // pass-1 fills for wrapping cells: proportional share of the internal
874	    // width over sibling occupancies
875	    let mut fill1 = vec![None::<i64>; n];
876	    for (i, sh) in shapes.iter().enumerate() {
877	        if !wrap1[i] {
878	            continue;
879	        }
880	        let flat = sh.flat as i64;
881	        if n == 1 {
882	            fill1[i] = Some(full);
883	            continue;
884	        }
885	        let num = ov(i)
886	            .and_then(|w| w.fill_width)
887	            .unwrap_or(flat + sh.rec_sur7 + sh.nfunc) as f64;
888	        let mut t = num;
889	        for j in 0..n {
890	            if j != i {
891	                let w = if shapes[j].sqa && (sh.tup_sur + sh.uni_sur) > 0 { 5.0 / 6.0 } else { 1.0 };
892	                t += w * cs[j] as f64;
893	            }
894	        }
895	        let b = hd((full as f64) * num / t).max(floor).min((flat - 1).max(floor));
896	        fill1[i] = Some(b);
897	    }
898	    // pass 2 (relief, round-11 battery I + TB/WIT): a pass-1-wrapping cell is
899	    // saved — renders flat — iff it fits in the room its siblings actually
900	    // occupy: a TRULY-BROKEN wrapping sibling (fill below its peel-only zone,
901	    // i.e. fill < flat − 2) is charged its fill allocation, everything else
902	    // its occupancy C. No bonus in this comparison (IB: a tuple target beside
903	    // a wrapping 90 fits only at the floor).
904	    let mut out = Vec::with_capacity(n);
905	    for (i, sh) in shapes.iter().enumerate() {
906	        let flat = sh.flat as i64;
907	        if !wrap1[i] {
908	            out.push(budget1[i].max(flat) as usize);
909	            continue;
910	        }
911	        if n > 1 {
912	            let mut tot = 0i64;
913	            for j in 0..n {
914	                if j != i {
915	                    let truly_broken =
916	                        wrap1[j] && fill1[j].map_or(false, |b| b < shapes[j].flat as i64 - 2);
917	                    tot += if truly_broken { fill1[j].unwrap() } else { cs[j] };
918	                }
919	            }
920	            let budget2 = (full - tot).max(floor);
921	            if eff[i] <= budget2 {
922	                out.push(budget2.max(flat) as usize);
923	                continue;
924	            }
925	        }
926	        out.push(fill1[i].unwrap() as usize);
927	    }
928	    out
929	}
