1	//! Corpus census of the record-cell wrap model (BEHAVIOR.md §3f).
2	//!
3	//! For every record in the corpus, parse its label into groups → cells, dewrap
4	//! each cell back to its flat (post-abbreviation) text, re-run several candidate
5	//! per-cell width allocators through the exact layout engine, and compare the
6	//! produced record-label bytes to the actual cell bytes. Reports byte-exactness
7	//! over wrapping prem/concl cells (the round-8 metric) and over all cells, per
8	//! allocator, in ONE corpus pass.
9	//!
10	//! Ignored by default; run with `GRAPHCLEAN_CORPUS=<dir> cargo test --release
11	//! --test fill_census -- --ignored --nocapture census`.
12	
13	use graph_clean::doclayout::wrap_cell_dot;
14	
15	fn split_top(s: &str, sep: char) -> Vec<String> {
16	    let chars: Vec<char> = s.chars().collect();
17	    let mut parts = Vec::new();
18	    let mut cur = String::new();
19	    let mut depth = 0i32;
20	    let mut i = 0;
21	    while i < chars.len() {
22	        let c = chars[i];
23	        if c == '\\' && i + 1 < chars.len() {
24	            cur.push(c);
25	            cur.push(chars[i + 1]);
26	            i += 2;
27	            continue;
28	        }
29	        match c {
30	            '{' => {
31	                depth += 1;
32	                cur.push(c);
33	            }
34	            '}' => {
35	                depth -= 1;
36	                cur.push(c);
37	            }
38	            _ if c == sep && depth == 0 => parts.push(std::mem::take(&mut cur)),
39	            _ => cur.push(c),
40	        }
41	        i += 1;
42	    }
43	    parts.push(cur);
44	    parts
45	}
46	
47	fn unescape(t: &str) -> String {
48	    t.replace("\\<", "<").replace("\\>", ">").replace("\\{", "{").replace("\\}", "}").replace("\\|", "|")
49	}
50	
51	fn parse_record(label: &str) -> Option<Vec<Vec<String>>> {
52	    if !(label.starts_with('{') && label.ends_with('}')) {
53	        return None;
54	    }
55	    let inner = &label[1..label.len() - 1];
56	    let mut groups = Vec::new();
57	    for g in split_top(inner, '|') {
58	        let g = g.trim();
59	        if !(g.starts_with('{') && g.ends_with('}')) {
60	            return None;
61	        }
62	        let gi = &g[1..g.len() - 1];
63	        groups.push(split_top(gi, '|'));
64	    }
65	    Some(groups)
66	}
67	
68	fn strip_port(cell: &str) -> Option<&str> {
69	    let rest = cell.strip_prefix("<n")?;
70	    let sp = rest.find("> ")?;
71	    if !rest[..sp].chars().all(|c| c.is_ascii_digit()) {
72	        return None;
73	    }
74	    Some(&rest[sp + 2..])
75	}
76	
77	fn is_info_body(body: &str) -> bool {
78	    body.starts_with('#') && body.contains(" : ")
79	}
80	
81	fn dewrap(body: &str) -> String {
82	    // `,\l` = a separator break (its trailing space is dropped at line end);
83	    // `\l&nbsp;` = an indented continuation or an indented closer peel (no
84	    // character lost); a remaining col-0 `\l)` = the fact-paren peel (its
85	    // padded ` )` space was the break). Order matters.
86	    let t = body.replace(",\\l", ", ");
87	    let t = t.replace("\\l&nbsp;", "&nbsp;");
88	    let t = t.replace("\\l)", " )");
89	    let t = t.replace("\\l", "").replace("&nbsp;", "");
90	    unescape(&t)
91	}
92	
93	fn flat_width(body: &str) -> usize {
94	    dewrap(body).chars().count()
95	}
96	
97	const FLOOR: usize = 20;
98	const W: usize = 87;
99	
100	// ---- candidate allocators: given the group's cell flats, per-cell width ----
101	
102	fn alloc_smallest_first(flats: &[usize]) -> Vec<usize> {
103	    let n = flats.len();
104	    let mut order: Vec<usize> = (0..n).collect();
105	    order.sort_by_key(|&i| flats[i]);
106	    let mut occ = flats.to_vec();
107	    let mut out = vec![0usize; n];
108	    for &i in &order {
109	        let others: usize = (0..n).filter(|&j| j != i).map(|j| occ[j]).sum();
110	        let b = W.saturating_sub(others).max(FLOOR);
111	        out[i] = b;
112	        occ[i] = flats[i].min(b);
113	    }
114	    out
115	}
116	
117	fn alloc_flatsum(flats: &[usize]) -> Vec<usize> {
118	    let t: usize = flats.iter().sum();
119	    (0..flats.len())
120	        .map(|i| W.saturating_sub(t - flats[i]).max(FLOOR))
121	        .collect()
122	}
123	
124	fn alloc_proportional(flats: &[usize]) -> Vec<usize> {
125	    let t: usize = flats.iter().sum();
126	    if t == 0 {
127	        return vec![W; flats.len()];
128	    }
129	    flats
130	        .iter()
131	        .map(|&f| ((W * f + t / 2) / t).max(FLOOR))
132	        .collect()
133	}
134	
135	fn alloc_prop_l(flats: &[usize], l: usize) -> Vec<usize> {
136	    let t: usize = flats.iter().sum();
137	    if t == 0 {
138	        return vec![W; flats.len()];
139	    }
140	    flats.iter().map(|&f| ((l * f + t / 2) / t).max(FLOOR)).collect()
141	}
142	
143	fn alloc_prop_ceil(flats: &[usize]) -> Vec<usize> {
144	    let t: usize = flats.iter().sum();
145	    if t == 0 {
146	        return vec![W; flats.len()];
147	    }
148	    flats.iter().map(|&f| ((W * f + t - 1) / t).max(FLOOR)).collect()
149	}
150	
151	/// Reserve cells whose flat ≤ FLOOR (they never wrap) at their flat width, then
152	/// distribute the remaining budget proportionally among the larger cells.
153	fn alloc_reserve_small(flats: &[usize]) -> Vec<usize> {
154	    let reserved: usize = flats.iter().filter(|&&f| f <= FLOOR).sum();
155	    let big_sum: usize = flats.iter().filter(|&&f| f > FLOOR).sum();
156	    if big_sum == 0 {
157	        return flats.iter().map(|&f| f.max(FLOOR)).collect();
158	    }
159	    let avail = W.saturating_sub(reserved).max(FLOOR);
160	    flats
161	        .iter()
162	        .map(|&f| {
163	            if f <= FLOOR {
164	                FLOOR
165	            } else {
166	                ((avail * f + big_sum / 2) / big_sum).max(FLOOR)
167	            }
168	        })
169	        .collect()
170	}
171	
172	struct Tally {
173	    name: String,
174	    wrap_total: usize,
175	    wrap_match: usize,
176	    all_total: usize,
177	    all_match: usize,
178	    // diagnostics (single vs multi cell groups; failure modes)
179	    single_wrap_total: usize,
180	    single_wrap_match: usize,
181	    multi_wrap_total: usize,
182	    multi_wrap_match: usize,
183	    // mismatch modes on wrapping cells
184	    fn_predict_oneline: usize, // actual wraps, predicted single line (false neg)
185	    fill_error: usize,         // both wrap, differ
186	    fp_examples: Vec<(String, usize, String, String)>, // flat, width, want, got
187	}
188	
189	fn main_census() {
190	    let Ok(corpus) = std::env::var("GRAPHCLEAN_CORPUS") else {
191	        eprintln!("set GRAPHCLEAN_CORPUS");
192	        return;
193	    };
194	    type Alloc = (&'static str, Box<dyn Fn(&[usize], &[String]) -> Vec<usize>>);
195	    let allocs: Vec<Alloc> = vec![
196	        (
197	            "crate group_widths",
198	            Box::new(|_f: &[usize], texts: &[String]| graph_clean::generate::group_widths(texts)),
199	        ),
200	        ("proportional(87)", Box::new(|f: &[usize], _t: &[String]| alloc_proportional(f))),
201	        ("prop_ceil", Box::new(|f: &[usize], _t: &[String]| alloc_prop_ceil(f))),
202	        ("reserve_small", Box::new(|f: &[usize], _t: &[String]| alloc_reserve_small(f))),
203	    ];
204	    let _ = (alloc_smallest_first, alloc_flatsum, alloc_prop_l);
205	    let mut tallies: Vec<Tally> = allocs
206	        .iter()
207	        .map(|(n, _)| Tally {
208	            name: n.to_string(),
209	            wrap_total: 0,
210	            wrap_match: 0,
211	            all_total: 0,
212	            all_match: 0,
213	            single_wrap_total: 0,
214	            single_wrap_match: 0,
215	            multi_wrap_total: 0,
216	            multi_wrap_match: 0,
217	            fn_predict_oneline: 0,
218	            fill_error: 0,
219	            fp_examples: Vec::new(),
220	        })
221	        .collect();
222	
223	    let step: usize = std::env::var("STEP").ok().and_then(|s| s.parse().ok()).unwrap_or(1);
224	    for (fi, entry) in std::fs::read_dir(&corpus).unwrap().enumerate() {
225	        if step > 1 && fi % step != 0 {
226	            continue;
227	        }
228	        let path = entry.unwrap().path();
229	        if path.extension().and_then(|e| e.to_str()) != Some("dot") {
230	            continue;
231	        }
232	        let dot = std::fs::read_to_string(&path).unwrap();
233	        for line in dot.lines() {
234	            if !line.contains("shape=\"record\"") {
235	                continue;
236	            }
237	            let Some(lstart) = line.find("label=\"") else { continue };
238	            let after = &line[lstart + 7..];
239	            let Some(lend) = after.find("\",fillcolor") else { continue };
240	            let label = &after[..lend];
241	            let Some(groups) = parse_record(label) else { continue };
242	            for cells in &groups {
243	                let bodies: Vec<&str> = match cells.iter().map(|c| strip_port(c)).collect::<Option<Vec<_>>>() {
244	                    Some(b) => b,
245	                    None => continue,
246	                };
247	                if bodies.iter().any(|b| is_info_body(b)) {
248	                    continue;
249	                }
250	                let flats: Vec<usize> = bodies.iter().map(|b| flat_width(b)).collect();
251	                let flat_texts: Vec<String> = bodies.iter().map(|b| dewrap(b)).collect();
252	                let single = bodies.len() == 1;
253	                for (ti, (_, alloc)) in allocs.iter().enumerate() {
254	                    let widths = alloc(&flats, &flat_texts);
255	                    for (k, body) in bodies.iter().enumerate() {
256	                        let predicted = wrap_cell_dot(&flat_texts[k], widths[k] as isize);
257	                        let is_wrap = body.contains("\\l");
258	                        let m = predicted == *body;
259	                        tallies[ti].all_total += 1;
260	                        if m {
261	                            tallies[ti].all_match += 1;
262	                        }
263	                        if is_wrap {
264	                            tallies[ti].wrap_total += 1;
265	                            if m {
266	                                tallies[ti].wrap_match += 1;
267	                            }
268	                            if single {
269	                                tallies[ti].single_wrap_total += 1;
270	                                if m {
271	                                    tallies[ti].single_wrap_match += 1;
272	                                }
273	                            } else {
274	                                tallies[ti].multi_wrap_total += 1;
275	                                if m {
276	                                    tallies[ti].multi_wrap_match += 1;
277	                                }
278	                            }
279	                            if !m {
280	                                if !predicted.contains("\\l") {
281	                                    tallies[ti].fn_predict_oneline += 1;
282	                                    if tallies[ti].fp_examples.len() < 25 && single {
283	                                        tallies[ti].fp_examples.push((
284	                                            flat_texts[k].clone(),
285	                                            widths[k],
286	                                            body.to_string(),
287	                                            predicted.clone(),
288	                                        ));
289	                                    }
290	                                } else {
291	                                    tallies[ti].fill_error += 1;
292	                                }
293	                            }
294	                        }
295	                    }
296	                }
297	            }
298	        }
299	    }
300	    for t in &tallies {
301	        eprintln!(
302	            "{:16} all {:>6}/{:<6}={:6.3}% | wrap {:>6}/{:<6}={:6.2}% | single {:>6}/{:<6}={:6.2}% | multi {:>6}/{:<6}={:6.2}% | falseNeg {:>5} fillErr {:>5}",
303	            t.name,
304	            t.all_match,
305	            t.all_total,
306	            100.0 * t.all_match as f64 / t.all_total.max(1) as f64,
307	            t.wrap_match,
308	            t.wrap_total,
309	            100.0 * t.wrap_match as f64 / t.wrap_total.max(1) as f64,
310	            t.single_wrap_match,
311	            t.single_wrap_total,
312	            100.0 * t.single_wrap_match as f64 / t.single_wrap_total.max(1) as f64,
313	            t.multi_wrap_match,
314	            t.multi_wrap_total,
315	            100.0 * t.multi_wrap_match as f64 / t.multi_wrap_total.max(1) as f64,
316	            t.fn_predict_oneline,
317	            t.fill_error,
318	        );
319	    }
320	    if std::env::var("SHOW_FP").is_ok() {
321	        // single-cell false-negatives for the proportional allocator (index 2)
322	        for (flat, w, want, got) in tallies[2].fp_examples.iter().take(20) {
323	            eprintln!("--- single-cell falseNeg  w={w}  flat({}): {flat}", flat.chars().count());
324	            eprintln!("    want: {want}");
325	            eprintln!("    got : {got}");
326	        }
327	    }
328	}
329	
330	#[test]
331	#[ignore]
332	fn census() {
333	    main_census();
334	}
